import React, { useState, useRef, useEffect } from 'react';
import { Bot, X, MessageSquare, Sparkles } from 'lucide-react';

export default function AIAssistant() {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState([
        { role: 'assistant', text: "Hi! I'm your AI Learning Assistant. Ask me how the credit system works, or how to publish a skill!" }
    ]);
    const [input, setInput] = useState('');
    const [loading, setLoading] = useState(false);
    const messagesEndRef = useRef(null);

    useEffect(() => {
        if (isOpen) {
            messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [messages, isOpen]);

    const handleSend = async (e) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMsg = { role: 'user', text: input };
        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setLoading(true);

        try {
            const res = await fetch('http://localhost:3001/api/ai/assistant', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ query: userMsg.text })
            });
            const data = await res.json();
            setMessages(prev => [...prev, { role: 'assistant', text: data.reply }]);
        } catch (err) {
            setMessages(prev => [...prev, { role: 'assistant', text: "Sorry, I'm currently offline." }]);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed bottom-6 right-6 z-50">
            {isOpen ? (
                <div className="bg-slate-800 border border-slate-700 rounded-2xl shadow-2xl w-80 sm:w-96 flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-5 duration-300 h-[500px]">
                    <div className="bg-gradient-to-r from-indigo-600 to-purple-600 p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-2 text-white">
                            <Sparkles size={20} />
                            <h3 className="font-bold">Gemini Assistant</h3>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="text-white/70 hover:text-white transition-colors">
                            <X size={20} />
                        </button>
                    </div>

                    <div className="flex-1 p-4 overflow-y-auto space-y-4 custom-scrollbar bg-slate-900/50">
                        {messages.map((msg, i) => (
                            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-indigo-500 text-white rounded-tr-sm' : 'bg-slate-800 border border-slate-700 text-slate-200 rounded-tl-sm'}`}>
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                        {loading && (
                            <div className="flex justify-start">
                                <div className="bg-slate-800 border border-slate-700 p-3 rounded-2xl rounded-tl-sm flex gap-1 items-center">
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{animationDelay: '0.4s'}}></div>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    <form onSubmit={handleSend} className="p-3 bg-slate-800 border-t border-slate-700 shrink-0">
                        <div className="relative">
                            <input 
                                type="text" 
                                value={input} 
                                onChange={e => setInput(e.target.value)}
                                placeholder="Ask me anything..." 
                                className="w-full bg-slate-900 border border-slate-600 rounded-full pl-4 pr-10 py-2.5 text-sm text-white focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
                            />
                            <button type="submit" disabled={!input.trim() || loading} className="absolute right-1.5 top-1.5 p-1.5 bg-indigo-500 hover:bg-indigo-600 disabled:opacity-50 text-white rounded-full transition-colors">
                                <Bot size={16} />
                            </button>
                        </div>
                    </form>
                </div>
            ) : (
                <button 
                    onClick={() => setIsOpen(true)}
                    className="bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-lg shadow-indigo-600/30 hover:scale-110 transition-all flex items-center justify-center relative group"
                >
                    <MessageSquare size={28} />
                    <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full border-2 border-slate-900"></span>
                </button>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Sparkles, X } from 'lucide-react';

export default function ReviewModal({ sessionId, onClose }) {
    const [suggestion, setSuggestion] = useState('');
    const [loading, setLoading] = useState(true);
    const [review, setReview] = useState('');

    useEffect(() => {
        const fetchAISuggestion = async () => {
            try {
                const res = await fetch('http://localhost:3001/api/ai/generate-review', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ sessionId })
                });
                const data = await res.json();
                setSuggestion(data.suggestion);
                setReview(data.suggestion);
            } catch (err) {
                console.error(err);
                setSuggestion('Great class!');
            } finally {
                setLoading(false);
            }
        };
        fetchAISuggestion();
    }, [sessionId]);

    const handleSubmit = (e) => {
        e.preventDefault();
        alert("Review submitted successfully!");
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm">
            <div className="bg-slate-800 rounded-2xl w-full max-w-lg border border-slate-700 shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                <div className="bg-gradient-to-r from-indigo-500 to-purple-600 p-6 relative">
                    <button onClick={onClose} className="absolute top-4 right-4 text-white/70 hover:text-white"><X size={20}/></button>
                    <h2 className="text-2xl font-bold text-white mb-2 flex items-center gap-2">
                        Session Completed!
                    </h2>
                    <p className="text-white/80 text-sm">Leave a review for your class.</p>
                </div>

                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <Sparkles size={16} className="text-indigo-400" />
                            <label className="text-sm font-medium text-slate-300">AI Suggested Review (Based on chat history)</label>
                        </div>
                        {loading ? (
                            <div className="h-24 bg-slate-700/50 animate-pulse rounded-lg border border-slate-600 flex items-center justify-center text-slate-400 text-sm">
                                Analyzing chat history with Gemini...
                            </div>
                        ) : (
                            <textarea 
                                className="w-full h-24 bg-slate-900 border border-slate-700 rounded-lg p-3 text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
                                value={review}
                                onChange={(e) => setReview(e.target.value)}
                            />
                        )}
                        <p className="text-xs text-slate-500 mt-2">Feel free to edit the AI's suggestion before submitting.</p>
                    </div>

                    <div className="flex justify-end gap-3">
                        <button type="button" onClick={onClose} className="px-4 py-2 rounded-lg text-slate-300 hover:bg-slate-700 transition-colors">Skip</button>
                        <button type="submit" disabled={loading} className="bg-indigo-500 hover:bg-indigo-600 disabled:opacity-50 text-white px-6 py-2 rounded-lg font-medium transition-colors shadow-lg shadow-indigo-500/20">Submit Review</button>
                    </div>
                </form>
            </div>
        </div>
    );
}

