                <div className="space-y-6">
                    <h2 className="text-xl font-bold flex items-center gap-2"><Award size={20} className="text-green-400" /> My Sessions</h2>
                    <div className="space-y-3">
                        {activeSessions.length === 0 ? (
                            <div className="text-sm p-4 glass rounded-xl text-center text-slate-400">No active sessions.</div>
                        ) : (
